  Object.assign(labels,{routine:'例行巡查',night:'夜間巡查',cash:'現金班（當日領現）',cash_payment:'現金',payroll_delivery:'薪資發放',pass:'合格',improvement_required:'限期改善',critical:'重大缺失',good:'良好',used:'已有使用痕跡',needs_improvement:'待改善',not_applicable:'不適用',none:'無須改善',in_progress:'改善中',verified:'已複查完成',security_equipment:'保全設備',repair:'修繕工程',fire_safety:'消防設備',electromechanical:'機電維護',staffing:'人力支援',net_30:'月結30天',net_45:'月結45天',net_60:'月結60天',cod:'貨到付款',borrowed:'借用中',returned:'已歸還',overdue:'已逾期',lost:'遺失',damaged:'損壞待處理'});
  const format = (key,value) => {
    if ((key==='employee_id'||key==='site_id') && value) {
      const list=key==='employee_id'?state.relations.employees:state.relations.sites;
      return list.find(row=>row.id===value)?.[key==='employee_id'?'full_name':'name'] || value;
    }
    if(key==='item_id'&&value)return state.relations.inventory_items.find(row=>row.id===value)?.item_name||value;
    if(key==='vendor_id'&&value)return state.relations.vendors.find(row=>row.id===value)?.name||value;
    if(key==='numbering_rule_id'&&value)return state.relations.numbering_rules.find(row=>row.id===value)?.rule_name||value;
    if(key==='target_type')return numberingTargetOptions.find(option=>option[0]===value)?.[1]||value;
    if(key==='salary_payment_method')return value==='cash'?'領現':value==='bank_transfer'?'銀行匯款':value||'—';
    if(key==='action')return({INSERT:'新增',UPDATE:'修改',DELETE:'刪除'})[value]||value;
    if (key==='start_time' && value) return value;
    if ((key==='clock_in'||key==='clock_out') && value) return value.replace('T',' ');
    return labels[value] || value || '—';
  };
  const badge = value => `<span class="badge ${['pending','late'].includes(value)?'warning':''} ${['inactive','missing','rejected'].includes(value)?'danger':''}">${esc(format('',value))}</span>`;
  const isBadge = key => ['status','display_status','role','shift_type','leave_type','renewal_status','transaction_type','category','is_active','is_manager','inspection_type','overall_result','follow_up_status','condition_out','condition_in'].includes(key);
